const componentRegistry=new Map();const renderCallbacks=new Map();export function registerComponent(id,component){if (componentRegistry.has(id)){console.warn(`[ComponentRegistry] Component "${id}" already registered,overwriting`)}componentRegistry.set(id,{id,name:component.name||id,type:component.type||'panel',render:component.render||(()=>{}),refresh:component.refresh||(()=>{}),destroy:component.destroy||(()=>{}),config:component.config||{},registeredAt:Date.now()});console.log(`[ComponentRegistry] Component "${id}" registered`)}export async function unregisterComponent(id){const component=componentRegistry.get(id);if (!component){throw new Error(`Component "${id}" not found`)}if (typeof component.destroy==='function'){try{await component.destroy()}catch (error){console.error(`[ComponentRegistry] Error destroying component "${id}":`,error)}}renderCallbacks.delete(id);componentRegistry.delete(id);console.log(`[ComponentRegistry] Component "${id}" unregistered`)}export function getComponent(id){return componentRegistry.get(id)||null}export function getAllComponents(){return Array.from(componentRegistry.values())}export function getComponentsByType(type){return getAllComponents().filter(c=>c.type===type)}export async function renderComponent(id,containerId,options={}){const component=componentRegistry.get(id);if (!component){throw new Error(`Component "${id}" not found`)}const container=document.getElementById(containerId);if (!container){throw new Error(`Container "${containerId}" not found`)}try{const result=await component.render(container,options);if (typeof result==='string'){container.innerHTML=result}else if (result&&typeof result==='object'){if (result.html){container.innerHTML=result.html}if (result.styles){injectStyles(result.styles,`plugin-${id}-styles`)}if (result.script){const scriptFn=new Function('component','container',result.script);scriptFn(component,container)}}console.log(`[ComponentRegistry] Component "${id}" rendered to "${containerId}"`);return result}catch (error){console.error(`[ComponentRegistry] Error rendering component "${id}":`,error);container.innerHTML=`<div class="error">组件渲染失败：${error.message}</div>`;throw error}}export async function refreshComponent(id,options={}){const component=componentRegistry.get(id);if (!component){throw new Error(`Component "${id}" not found`)}if (typeof component.refresh==='function'){try{await component.refresh(options)}catch (error){console.error(`[ComponentRegistry] Error refreshing component "${id}":`,error);throw error}}}export async function refreshAllComponents(options={}){const promises=Array.from(componentRegistry.values()).map(async (component)=>{try{await refreshComponent(component.id,options)}catch (error){console.error(`[ComponentRegistry] Error refreshing component "${component.id}":`,error)}});await Promise.all(promises)}export function setAutoRefresh(id,interval){clearAutoRefresh(id);const timerId=setInterval(async ()=>{try{await refreshComponent(id)}catch (error){console.error(`[ComponentRegistry] Auto-refresh failed for "${id}":`,error)}},interval);renderCallbacks.set(id,timerId);console.log(`[ComponentRegistry] Auto-refresh set for "${id}" (interval:${interval}ms)`)}export function clearAutoRefresh(id){const timerId=renderCallbacks.get(id);if (timerId){clearInterval(timerId);renderCallbacks.delete(id);console.log(`[ComponentRegistry] Auto-refresh cleared for "${id}"`)}}export function clearAllAutoRefresh(){renderCallbacks.forEach((timerId,id)=>{clearInterval(timerId)});renderCallbacks.clear();console.log('[ComponentRegistry] All auto-refresh cleared')}function injectStyles(css,id){let styleEl=document.getElementById(id);if (!styleEl){styleEl=document.createElement('style');styleEl.id=id;document.head.appendChild(styleEl)}styleEl.textContent=css}export function createWidget(options={}){const{id,title='Widget',width='medium',height='auto',refreshable=true,collapsible=true}=options;const widget=document.createElement('div');widget.className=`dashboard-widget widget-${width}`;widget.dataset.componentId=id;const header=document.createElement('div');header.className='widget-header';const titleEl=document.createElement('h3');titleEl.className='widget-title';titleEl.textContent=title;header.appendChild(titleEl);if (refreshable||collapsible){const actions=document.createElement('div');actions.className='widget-actions';if (refreshable){const refreshBtn=document.createElement('button');refreshBtn.className='widget-action refresh';refreshBtn.innerHTML='🔄';refreshBtn.title='刷新';refreshBtn.onclick=()=>refreshComponent(id);actions.appendChild(refreshBtn)}if (collapsible){const collapseBtn=document.createElement('button');collapseBtn.className='widget-action collapse';collapseBtn.innerHTML='▼';collapseBtn.title='折叠';collapseBtn.onclick=()=>{const content=widget.querySelector('.widget-content');if (content){content.style.display=content.style.display==='none'?'block':'none';collapseBtn.innerHTML=content.style.display==='none'?'▶':'▼'}};actions.appendChild(collapseBtn)}header.appendChild(actions)}const content=document.createElement('div');content.className='widget-content';content.id=`widget-${id}-content`;widget.appendChild(header);widget.appendChild(content);return widget}export async function renderDashboard(componentIds,containerId){const container=document.getElementById(containerId);if (!container){throw new Error(`Container "${containerId}" not found`)}container.innerHTML='';container.className='dashboard-grid';for (const id of componentIds){const component=componentRegistry.get(id);if (!component){console.warn(`[ComponentRegistry] Component "${id}" not found,skipping`);continue}const widget=createWidget({id,title:component.name,refreshable:typeof component.refresh==='function'});container.appendChild(widget);const contentEl=document.getElementById(`widget-${id}-content`);if (contentEl){await renderComponent(id,contentEl)}}}export async function loadComponentsFromPlugin(pluginConfig){const{id,name,type,config}=pluginConfig;if (type==='panel'){registerComponent(id,{name:name||id,type:'panel',config:config||{},render:async (container)=>{return{html:`<div class="plugin-panel" data-plugin="${id}"><div class="loading">加载插件面板...</div></div>`,styles:`.plugin-panel{padding:16px;min-height:200px}.plugin-panel .loading{color:#64748b;text-align:center;padding:40px}`}},refresh:async ()=>{console.log(`[ComponentRegistry] Refreshing plugin component "${id}"`)}})}}export function initComponentRegistry(){console.log('[ComponentRegistry] Initialized');window.addEventListener('beforeunload',()=>{clearAllAutoRefresh()})}export default{registerComponent,unregisterComponent,getComponent,getAllComponents,getComponentsByType,renderComponent,refreshComponent,refreshAllComponents,setAutoRefresh,clearAutoRefresh,clearAllAutoRefresh,createWidget,renderDashboard,loadComponentsFromPlugin,initComponentRegistry};